-- Query: 000AuditReport_OLD
SELECT [000AuditSessionSelect].CustomerID, [000AuditSessionSelect].LastName, [000AuditSessionSelect].FirstName, [000AuditSessionSelect].Gender, [000AuditSessionSelect].Address, [000AuditSessionSelect].City, [000AuditSessionSelect].State, [000AuditSessionSelect].ZipCode, [000AuditSessionSelect].Phone, [000AuditSessionSelect].StudentID, [000AuditSessionSelect].SchoolID, [000AuditSessionSelect].WebPassword, [000AuditSessionSelect].SessionNumber, [000AuditSessionSelect].SessionID, [000AuditSessionSelect].SessionItemID, [000AuditSessionSelect].Description, [000AuditSessionSelect].DateTime, [000AuditSessionSelect].TotalDue, [000AuditSessionSelect].Payments, [000AuditSessionSelect].SalesTaxRate, [000AuditSessionTotalSession].SessionTotal, IIf(IsNull([000AuditSessionsTotalPayments].[TotalPayments]),0,[000AuditSessionsTotalPayments].[TotalPayments]) AS TotalPayments, IIf(IsNull([000AuditSessionDeposit].[TotalDeposit]),0,[000AuditSessionDeposit].[TotalDeposit]) AS TotalDeposit, IIf(IsNull([OrderTotal]),0,[OrderTotal]) AS OrderBalDue, IIf(IsNull([000AuditOrdersAmount].[TotalOrder]),0,[000AuditOrdersAmount].[TotalOrder]) AS TotalOrder, IIf(IsNull([000AuditOrdersTotalPayments].[TotalOrderPayments]),0,[000AuditOrdersTotalPayments].[TotalOrderPayments]) AS TotalOrderPayments, Schools.School
FROM (((((000AuditSessionSelect LEFT JOIN 000AuditSessionsTotalPayments ON [000AuditSessionSelect].SessionID = [000AuditSessionsTotalPayments].SessionID) LEFT JOIN 000AuditSessionDeposit ON [000AuditSessionSelect].SessionID = [000AuditSessionDeposit].SessionID) LEFT JOIN 000AuditOrdersAmount ON [000AuditSessionSelect].CustomerID = [000AuditOrdersAmount].CustomerID) LEFT JOIN 000AuditOrdersTotalPayments ON [000AuditSessionSelect].CustomerID = [000AuditOrdersTotalPayments].CustomerID) LEFT JOIN 000AuditSessionTotalSession ON ([000AuditSessionSelect].SessionID = [000AuditSessionTotalSession].SessionID) AND ([000AuditSessionSelect].CustomerID = [000AuditSessionTotalSession].CustomerID)) LEFT JOIN Schools ON [000AuditSessionSelect].SchoolID = Schools.SchoolID;

